
.world-section {
  padding: 12px;
}

.title-row {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 10px;
  margin-bottom: 10px;
}

.eyebrow {
  color: var(--qyc-vermilion-faded);
  font-family: var(--qyc-font-mono);
  font-size: 12px;
  letter-spacing: 0.12em;
}

h1 {
  margin: 2px 0 0;
  font-size: 18px;
  line-height: 1.2;
  font-family: var(--qyc-font-title);
  letter-spacing: 0.06em;
}

.live-badge {
  border: 2px solid var(--qyc-ok);
  border-radius: 999px;
  color: var(--qyc-ok);
  font-family: var(--qyc-font-mono);
  font-size: 13px;
  padding: 3px 10px;
}

.meta-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(128px, 1fr));
  gap: 6px;
  color: var(--qyc-ink);
  font-size: 14px;
}

.event-row {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  align-items: center;
  margin-top: 10px;
  border-top: 1px dashed var(--qyc-line-strong);
  padding-top: 10px;
}

.event-label,
.meeting-badge {
  border: 1px solid var(--qyc-line-strong);
  border-radius: 999px;
  color: var(--qyc-ink-dim);
  font-size: 14px;
  padding: 4px 10px;
}

.meeting-badge.active {
  border-color: var(--qyc-vermilion);
  background: rgba(184, 56, 30, 0.08);
  color: var(--qyc-vermilion);
}

.event-text {
  flex: 1 1 220px;
  color: var(--qyc-ink);
  font-size: 15px;
}
